form:Form.form:Scripts:
		function CusonLoad()
{
	//Invoca al OnLoad del Base.
	OnLoad(); 	

	if(Ctrl('main').GetMode()=='NEW')
	{
		if(Ctrl('lv_comprobantes').TotalRowsCount()==0)
		{
			CtrlEnabled('oi_empresa',true);	
			CtrlEnabled('oi_carpeta',true);
			CtrlEnabled('oi_adelanto',true);		
		}
		else
		{
			CtrlEnabled('oi_empresa',false);
			CtrlEnabled('oi_carpeta',false);
			CtrlEnabled('oi_adelanto',false);
		}

		////////////////////////////////////////////////////
		/*Ctrl('oi_empresa').SetXValue('182');
		Ctrl('oi_carpeta').SetXValue('112');
		Ctrl('oi_adelanto').SetXValue('902');
		Ctrl('f_rendicion').SetXValue(datetime2str(Now()));*/
		////////////////////////////////////////////////////		
	} 

	//Si es modo SHOW, completo los campos informativos <<<TODO>>>
	if(Ctrl('main').GetMode()=='SHOW')
	{
	  var oi_rendicion = Ctrl('ID').GetXValue();   
	  var nSQL = GetProxy().SQLService();
	  var xmlParam = new NomadXML('DATA');
	  xmlParam.SetAtrr('oi_rendicion', oi_rendicion);		

		//Recupero los datos para el modo SHOW
		var objResult = nSQL.GetOBJ(Ctrl("main").getResource("GET_DATOS_SHOW"), xmlParam.ToString());

		//Completo los campos
		Ctrl('oi_empresa').SetCValue(objResult.oi_empresa);
		Ctrl('oi_carpeta').SetCValue(objResult.oi_carpeta);						
		Ctrl('responsable').SetCValue(objResult.responsable);		
		Ctrl('montoAdelanto').SetCValue(objResult.n_monto_adel);
		Ctrl('montoARendir').SetCValue(objResult.n_monto_a_rendir);
		Ctrl('sucursal').SetCValue(objResult.sucursal);
		Ctrl('cliente').SetCValue(objResult.cliente);
	}
}


//Agrega un Comprobante
function btnAdd_onclick()
{
	if (Ctrl('oi_adelanto').GetXValue()=="")
	{
		alert("Para agregar comprobantes de la rendición seleccione primero una carpeta y un adelanto.");
		return false;
	}	
	return true;	
}


//Edita comprobante seleccionado
function btnEditComp_onclick()
{
	if(Ctrl('lv_comprobantes').TotalRowsCount()==0)
	{	
		alert("No hay comprobantes cargados.");
		return false; 
	}

  return true; 
}


//Borra comprobante seleccionado
function btnDelComp_onclick()
{	
	if(Ctrl('lv_comprobantes').TotalRowsCount()==0)
	{	
		alert("No hay comprobantes cargados.");
		return false;
	}

	var confirma = confirm("¿Está seguro que desea eliminar el comprobante seleccionado?");
	if (!confirma) return false;	

	return true;	
}


//Muestra comprobante seleccionado
function btnShowComp_onclick()
{
	if(Ctrl('lv_comprobantes').TotalRowsCount()==0)
	{	
		alert("No hay comprobantes cargados.");
		return false; 
	}

  return true; 
}



function adelanto_onchange()
{ 
  var oi_adelanto = Ctrl('oi_adelanto').GetXValue();

  if(oi_adelanto =="")
  {	  
		Ctrl('responsable').SetXValue('');	 
		Ctrl('montoAdelanto').SetXValue('');
		Ctrl('montoARendir').SetXValue('');  
		//Ctrl('oi_centro_costo').SetXValue('');
		Ctrl('sucursal').SetXValue('');
		Ctrl('cliente').SetXValue('');
		//Ctrl('oi_negociacion').SetXValue('');		
  }
  else
  {
	  var nSQL = GetProxy().SQLService();	  
	  var xmlParam = new NomadXML('DATA');
	  xmlParam.SetAtrr('oi_adelanto', oi_adelanto);	  

		//Recupero los datos del adelanto para el oi_adelanto seleccionado en el combo
		var objDatosAdelanto = nSQL.GetOBJ(Ctrl("main").getResource("GET_DATOS_ADELANTOS"), xmlParam.ToString());

		//Seteo los campos informativos del adelanto		
		Ctrl('responsable').SetXValue(objDatosAdelanto.responsable);
		Ctrl('montoAdelanto').SetXValue(objDatosAdelanto.n_monto_adel);
		Ctrl('montoARendir').SetXValue(objDatosAdelanto.n_monto_a_rendir);
		//Ctrl('oi_centro_costo').SetXValue(objDatosAdelanto.oi_centro_costo);
		Ctrl('sucursal').SetXValue(objDatosAdelanto.sucursal);
		Ctrl('cliente').SetXValue(objDatosAdelanto.cliente);
		//Ctrl('oi_negociacion').SetXValue(objDatosAdelanto.oi_negociacion);
  }                          
}


function ACCEPT_onValidate(pObj)
{
  //Valida que haya comprobantes cargados
	if(Ctrl('lv_comprobantes').TotalRowsCount()==0)
	{
		pObj.SetError("Debe ingresar al menos un Comprobante.");
		return false;		
	}

	//Valida que el monto de la rendicion no supere el monto por rendir
  var montoARendir = Number(Ctrl('montoARendir').GetXValue());
  var montoRendicion = Number(Ctrl('n_monto_rendicion').GetXValue());	        
	if(montoRendicion > montoARendir)
	{
  	pObj.SetError('El monto de la Rendición no puede superar el monto pendiente del Adelanto.');
  	return false;
  }

	return true;
}


//Si vuelve del show limpio el oi_adelanto por el filter
function cleanBack()
{
	if(Ctrl('main').GetMode()=='SHOW')
	{
		Ctrl('oi_adelanto').SetXValue('');
		return true;	
	}
}
